import { toServerItemLeaderboardRecordDetails, } from '../../../../models/server/items/leaderboards/records/details.js';
import { handleError } from '../../../error.js';
export const createServerItemLeaderboardRecordDetailsRouteHandler = (sonolus, group) => async ({ req, res, localize, ctx }) => {
    if (!group.leaderboard.record.detailsHandler) {
        res.status(404).end();
        return;
    }
    const itemName = req.params.itemName;
    if (!itemName) {
        res.status(400).end();
        return;
    }
    const leaderboardName = req.params.leaderboardName;
    if (!leaderboardName) {
        res.status(400).end();
        return;
    }
    const recordName = req.params.recordName;
    if (!recordName) {
        res.status(400).end();
        return;
    }
    const response = await group.leaderboard.record.detailsHandler({
        ...ctx,
        itemName,
        leaderboardName,
        recordName,
    });
    if (handleError(response, res, localize))
        return;
    res.json(toServerItemLeaderboardRecordDetails(sonolus, localize, response));
};
